using NBitcoin;
using WalletWasabi.Backend.Models;
using WalletWasabi.Blockchain.Blocks;

namespace WalletWasabi.Blockchain.BlockFilters;

public static class StartingFilters
{
	public static FilterModel GetStartingFilter(Network network)
	{
		var startingHeader = SmartHeader.GetStartingHeader(network);

		var filter = network switch
		{
			_ when network == Network.Main =>
				"",
			_ when network == Network.TestNet => "01976d88",
			_ when network == Network.RegTest => "014756c0",
			_ when network == Bitcoin.Instance.Signet => "012e7640"
		};
		return new FilterModel(startingHeader, new GolombRiceFilter(Convert.FromHexString(filter)));
	}
}
